# So we have figures 1-11 (11 total) and tables 1-16 (16 total)
# Need to determine which are in main vs appendix

import PyPDF2
import re

pdf_path = '/tmp_workspace/pdf_2603.00155.pdf'
with open(pdf_path, 'rb') as f:
    reader = PyPDF2.PdfReader(f)

    page_texts = []
    for i, page in enumerate(reader.pages):
        try:
            page_text = page.extract_text() or ""
        except:
            page_text = ""
        page_texts.append((i+1, page_text))

# Find appendix start - look for Appendix A heading
appendix_start = None
for page_num, page_text in page_texts:
    # Look for lines like "A Additional Research Questions" or "Appendix"
    for line in page_text.split('\n'):
        stripped = line.strip()
        # Looking for "Appendix" as a standalone section header
        if re.match(r'^Appendix\s*$', stripped, re.I):
            appendix_start = page_num
            print(f"Found 'Appendix' at page {page_num}")
            break
        # Or "A Some text" style appendix header
        if re.match(r'^A\s+Additional\s+Research\s+Questions', stripped):
            appendix_start = page_num
            print(f"Found appendix at page {page_num}: {stripped}")
            break
    if appendix_start:
        break

# Alternative: find where main paper ends (typically after References)
ref_start = None
for page_num, page_text in page_texts:
    if 'References' in page_text:
        for line in page_text.split('\n'):
            if line.strip() == 'References':
                ref_start = page_num
                print(f"References found at page {page_num}")
                break

print(f"\nRef start: {ref_start}, Appendix start: {appendix_start}")

# Determine main and appendix pages
# Main = before references (typically), appendix = after
if appendix_start is None and ref_start:
    # Look for appendix after references
    for page_num, page_text in page_texts:
        if page_num > ref_start:
            for line in page_text.split('\n'):
                stripped = line.strip()
                if re.match(r'^A\s+\w', stripped) or re.match(r'^Appendix', stripped, re.I):
                    appendix_start = page_num
                    print(f"Found appendix (post-refs) at page {page_num}: {stripped}")
                    break
            if appendix_start:
                break

print(f"\nFinal appendix start page: {appendix_start}")

# Count figures and tables in each section
main_figs = set()
appendix_figs = set()
main_tables = set()
appendix_tables = set()

for page_num, page_text in page_texts:
    # Find figure captions (lines starting with "Figure N:" that are likely captions)
    is_appendix_page = appendix_start is not None and page_num >= appendix_start

    figs = re.findall(r'(?:^|\n)(?:Figure|Fig\.?)\s*(\d+):', page_text, re.MULTILINE | re.I)
    tables = re.findall(r'(?:^|\n)Table\s*(\d+):', page_text, re.MULTILINE | re.I)

    for f in figs:
        if is_appendix_page:
            appendix_figs.add(int(f))
        else:
            main_figs.add(int(f))

    for t in tables:
        if is_appendix_page:
            appendix_tables.add(int(t))
        else:
            main_tables.add(int(t))

print(f"\nMain figures: {sorted(main_figs)}")
print(f"Appendix figures: {sorted(appendix_figs)}")
print(f"Main tables: {sorted(main_tables)}")
print(f"Appendix tables: {sorted(appendix_tables)}")
PYEOF

